mapper.select:
sp.saving_product_id AS savingProductId, sp.kor_co_nm AS korCoNm, sp.fin_prdt_cd AS finPrdtCd, sp.fin_prdt_nm AS finPrdtNm, sp.max_limit AS maxLimit, sp.spcl_cnd AS benefit,
/* 즐겨찾기 여부 */ CASE WHEN EXISTS ( SELECT 1 FROM user_favorites uf WHERE uf.saving_product_id = sp.saving_product_id AND uf.user_id = #{userId} ) THEN TRUE ELSE FALSE END AS isStarred,
/* 좋아요 개수 */ COALESCE(lc.like_count, 0) AS likeCount,
/* 내가 좋아요 했는지 */
CASE WHEN EXISTS ( SELECT 1 FROM user_likes ul WHERE ul.saving_product_id = sp.saving_product_id AND ul.user_id = #{userId} ) THEN TRUE ELSE FALSE END AS isLiked,
FALSE AS isLiked,
FROM saving_product sp
/* 좋아요 개수 집계 (적금만) */ LEFT JOIN ( SELECT saving_product_id, COUNT(DISTINCT user_id) AS like_count FROM user_likes WHERE saving_product_id IS NOT NULL GROUP BY saving_product_id ) lc ON lc.saving_product_id = sp.saving_product_id
WHERE 1 = 1
AND sp.kor_co_nm LIKE CONCAT('%', #{korCoNm}, '%')
AND CAST(REPLACE(sp.max_limit, ',', '') AS UNSIGNED) <= #{maxLimit}
